// ── Room resolver ─────────────────────────────────────────────────────────
const roomMap = {
  'torre badum':662792,'torre':662792,
  'cala el pebret':662793,'pebret':662793,'el pebret':662793,
  'cala aljub':662794,'aljub':662794,
  'ermita sant antoni':662795,'ermita':662795,'sant antoni':662795,
};
const nameFromId = {662792:'Torre Badum',662793:'Cala El Pebret',662794:'Cala Aljub',662795:'Ermita Sant Antoni'};
const resolveRoom = (idOrName) => {
  let id = parseInt(idOrName);
  if (!isNaN(id) && nameFromId[id]) return { id, name: nameFromId[id] };
  const key = String(idOrName || '').toLowerCase().trim();
  id = roomMap[key] || null;
  if (!id) {
    for (const [k, v] of Object.entries(roomMap)) {
      if (key.includes(k) || k.includes(key)) { id = v; break; }
    }
  }
  return { id: id || null, name: nameFromId[id] || String(idOrName || 'habitación') };
};
// ─────────────────────────────────────────────────────────────────────────

if (action === 'beds24.updatePrice' || action === 'beds24.blockRoom') {
  const room = resolveRoom(p.roomId || p.roomName);
