} else if (action === 'beds24.getArrivals' || action === 'beds24.getDepartures' || action === 'beds24.getDailySummary') {
  requestBody = { date: p.date || p.startDate || today, token };

} else if (action === 'beds24.getGuestInfo') {
  const room = resolveRoom(p.roomId || p.roomName);
  resolvedRoomId   = room.id;
  resolvedRoomName = room.name;
  requestBody = { roomId: room.id, date: p.date || today, token };

} else if (action === 'tastyigniter.createReservation') {
  requestBody = {
    nombre:        p.nombre || p.name    || '(sin nombre)',
    email:         p.email              || 'noreply@portadirta.com',
    telefono:      p.telefono || p.phone || '000000000',
    personas:      parseInt(p.guests || p.personas || 2),
    fecha:         p.date || p.fecha    || today,
    hora:          p.hora               || '13:00',
    observaciones: p.observaciones      || '',
  };

} else if (action === 'tastyigniter.cancelReservation') {
  requestBody = {
    name: p.name || p.nombre || '',
    date: p.date || null,
  };
}
// GET actions — no body needed (requestBody stays null)

return [{ json: {
  ...inp,
  endpoint,
  method,
  requestBody,
  resolvedRoomId,
  resolvedRoomName,
} }];

// Extract natural language text from Claude, fallback to raw summary
const naturalText = items[0].json.choices?.[0]?.message?.content || items[0].json.choices?.[0]?.message?.content || items[0].json.content?.[0]?.text || '';
const ctx = $('Format Response').first().json;
return [{ json: { ...ctx, summary: naturalText || ctx.summary } }];

const identity = $('Identity Router').first().json;
