if (action === 'maintenance.addNote') {
  const noteText = p.note || p.text || p.mensaje || '';
  if (!noteText.trim()) {
    summary = '❌ No encontré el texto de la nota. Ej: "Apunta que el grifo de Torre Badum gotea"';
  } else {
    const id = Date.now().toString(36);
    sd.maintenanceNotes.push({ id, text: noteText, ts: new Date().toISOString(), addedBy: ctx.tier || 'admin' });
    summary = `🔧 Nota apuntada (${sd.maintenanceNotes.length} total): "${noteText}"`;
  }
} else if (action === 'maintenance.listNotes') {
  const notes = sd.maintenanceNotes || [];
  if (!notes.length) {
    summary = '📋 No hay notas de mantenimiento pendientes.';
  } else {
    const lines = notes.map((n, i) => `${i+1}. ${n.text} _(${n.ts.slice(0,10)})_`);
    summary = `🔧 *Notas de mantenimiento (${notes.length}):*\n` + lines.join('\n');
  }
} else {
  summary = `❓ Acción desconocida: ${action}`;
}

return [{ json: { ...ctx, summary, chatId: ctx.chatId } }];

const sd = $getWorkflowStaticData('global');
sd.processedEmails = sd.processedEmails || {};

const email = items[0].json;

// Derive stable key from message-id header (unique per RFC 2822) or fallback
const rawId = (email.headers?.['message-id'] || email.messageId || '')
  .replace(/[<>]/g, '').trim();
const fallbackId = (email.from || '') + '|' + (email.subject || '') + '|' + (email.date || '');
const idSource = rawId || fallbackId;

// Block self-email loops (prevent infinite reply chains)
const from = String(email.from || '').toLowerCase();
if (from.includes('portadirta.com')) return [];

// Use FULL base64 (no truncation) — old code truncated to 24 chars causing all emails
// from the same sender (whose address > 18 chars) to collide on the same key.
const msgKey = Buffer.from(idSource).toString('base64').replace(/[^a-zA-Z0-9]/g, '_');

// Block already-seen emails
if (sd.processedEmails[msgKey]) return [];

// Migrate: delete old ≤24-char truncated keys and entries older than 24h
const cutoff24h = Date.now() - 24 * 3600000;
for (const k of Object.keys(sd.processedEmails)) {
  if (k.length <= 24 || (sd.processedEmails[k]?.ts || 0) < cutoff24h) {
    delete sd.processedEmails[k];
  }
}

// Mark as seen immediately
sd.processedEmails[msgKey] = { ts: Date.now(), status: 'processing' };

// Strip HTML to plain text
const stripHtml = (h) => String(h || '')
  .replace(/<style[\s\S]*?<\/style>/gi, '')
  .replace(/<[^>]+>/g, ' ')
  .replace(/\s+/g, ' ').trim();

const bodyText = (email.text || stripHtml(email.html || '') || '').substring(0, 3000);

return [{ json: { msgKey, from: email.from, subject: email.subject, bodyText, date: email.date } }];

