const sd = $getWorkflowStaticData('global');
sd.pendingDrafts = sd.pendingDrafts || {};

const idempotency = $('Email Idempotency').first().json;
const { msgKey, from, subject, bodyText } = idempotency;
const raw = items[0].json.choices?.[0]?.message?.content || items[0].json.content?.[0]?.text || '{}';

let draft;
try {
  const clean = raw.replace(/^```json\s*/i, '').replace(/```\s*$/, '').trim();
  draft = JSON.parse(clean);
} catch(e) {
  draft = {
    draftSubject: 'Re: ' + subject,
    draftBody: "Gracias por contactar con Porta D'Irta. Hemos recibido tu mensaje y nos pondremos en contacto contigo a la mayor brevedad.\n\nEl equipo de Porta D'Irta",
    language: 'es',
    intent: 'other'
  };
}

// ── Beds24 real availability enrichment ──────────────────────────────────────
const emailBody = String(bodyText || '').toLowerCase();

// Detect booking intent: mentions of months or specific dates
const monthMap = {
  enero:1,february:2,febrero:2,march:3,marzo:3,april:4,abril:4,
  may:5,mayo:5,june:6,junio:6,july:7,julio:7,august:8,agosto:8,
  september:9,septiembre:9,october:10,octubre:10,november:11,noviembre:11,december:12,diciembre:12
};

// Extract check-in / check-out dates
let checkIn = null, checkOut = null;
const year = new Date().getFullYear();

// Pattern: "del 10 al 17 de agosto"
const rangeMatch = emailBody.match(/del?\s+(\d{1,2})\s+al?\s+(\d{1,2})\s+(?:de\s+)?(\w+)/);
if (rangeMatch) {
  const m = monthMap[rangeMatch[3]];
  if (m) {
    const d1 = rangeMatch[1].padStart(2,'0');
    const d2 = rangeMatch[2].padStart(2,'0');
    const mm = String(m).padStart(2,'0');
    checkIn  = `${year}-${mm}-${d1}`;
    checkOut = `${year}-${mm}-${d2}`;
  }
}

// Pattern: "del 10/08 al 17/08"
if (!checkIn) {
  const dateMatch = emailBody.match(/(\d{1,2})[\/\-](\d{1,2})(?:[\/\-]\d{2,4})?\s+(?:al?|to|-)\s+(\d{1,2})[\/\-](\d{1,2})/);
  if (dateMatch) {
    checkIn  = `${year}-${dateMatch[2].padStart(2,'0')}-${dateMatch[1].padStart(2,'0')}`;
    checkOut = `${year}-${dateMatch[4].padStart(2,'0')}-${dateMatch[3].padStart(2,'0')}`;
  }
}

// If no exact range, check for just a month mention
let mentionedMonth = null;
for (const [word, num] of Object.entries(monthMap)) {
  if (emailBody.includes(word)) { mentionedMonth = num; break; }
}
if (!checkIn && mentionedMonth) {
  const mm = String(mentionedMonth).padStart(2,'0');
  checkIn  = `${year}-${mm}-01`;
  checkOut = `${year}-${mm}-28`;
}

// Fetch real availability if we have dates
if (checkIn && checkOut && (draft.intent === 'booking' || emailBody.includes('reserv') || emailBody.includes('habitaci') || emailBody.includes('room') || emailBody.includes('disponib'))) {
  try {
    const tokenResp = await $helpers.httpRequest({
      method: 'GET',
      url: 'https://beds24.com/api/v2/authentication/token',
      headers: { refreshToken: $env.BEDS24_API_TOKEN }
    });

    const bookingsResp = await $helpers.httpRequest({
      method: 'GET',
      url: `https://beds24.com/api/v2/bookings?propId=318433&firstNight=${checkIn}&lastNight=${checkOut}`,
      headers: { token: tokenResp.token }
    });

    const TOTAL_ROOMS = 4;
    const activeStatuses = ['new','confirmed','checkin','checkout'];
    const bookings = (bookingsResp.data || []).filter(b => activeStatuses.includes(b.status));
    const bookedRoomIds = [...new Set(bookings.map(b => b.unitId))];
    const freeRooms = TOTAL_ROOMS - bookedRoomIds.length;

    let availLine;
    if (freeRooms >= TOTAL_ROOMS) {
      availLine = `✅ Tenemos disponibilidad completa del ${checkIn} al ${checkOut}. ¡Le recomendamos reservar cuanto antes!`;
    } else if (freeRooms > 0) {
      availLine = `⚡ Quedan ${freeRooms} habitación${freeRooms>1?'es':''} disponibles del ${checkIn} al ${checkOut}. ¡Plazas limitadas!`;
    } else {
      availLine = `😔 Lo sentimos, el hotel está completo del ${checkIn} al ${checkOut}. ¿Puedo sugerirle otras fechas?`;
    }

    // Replace the generic "check website" line with real availability
    let body = draft.draftBody || '';
    body = body.replace(
      /(?:te invitamos a visitarnos en[^.]*\.|consulta(?:r)?[^.]*portadirta\.com\/hotel[^.]*\.|please (?:check|visit)[^.]*website[^.]*\.)/gi,
      availLine + '\n\nReserva directa: https://www.portadirta.com/hotel\n'
    );
    // If no replacement happened, append before the sign-off
    if (body === draft.draftBody) {
      const signoff = body.lastIndexOf('\nEl equipo');
      if (signoff > 0) {
        body = body.substring(0, signoff) + '\n\n' + availLine + '\n\nReserva: https://www.portadirta.com/hotel\n' + body.substring(signoff);
      } else {
        body = body + '\n\n' + availLine + '\nReserva: https://www.portadirta.com/hotel';
      }
    }
    draft.draftBody = body;
  } catch(err) {
    // Beds24 unavailable — keep Claude's draft as-is
  }
}

// Store draft
sd.pendingDrafts[msgKey] = {
  to:      from,
  subject: draft.draftSubject || ('Re: ' + subject),
  body:    draft.draftBody    || '',
  intent:  draft.intent       || 'other',
  ts:      Date.now()
};

// Expire drafts older than 48h
const cutoff = Date.now() - 48 * 3600000;
for (const k of Object.keys(sd.pendingDrafts)) {
  if (sd.pendingDrafts[k].ts < cutoff) delete sd.pendingDrafts[k];
}

const preview = (draft.draftBody || '').length > 600
  ? draft.draftBody.substring(0, 600) + '…'
  : draft.draftBody;

const adminId = $env.TELEGRAM_ADMIN_ID;
const msg = `📧 *Nuevo email*\n`
          + `De: \`${from}\`\n`
          + `Asunto: _${subject}_\n\n`
          + `*Borrador:*\n${preview}`;

return [{ json: { msg, msgKey, adminId: String(adminId) } }];

