parameters.jsCode:
const sd = $getWorkflowStaticData('global');
sd.pendingDrafts   = sd.pendingDrafts   || {};
sd.processedEmails = sd.processedEmails || {};

const cb   = items[0].json.callbackData || '';
const chatId = String(items[0].json.chatId || $env.TELEGRAM_ADMIN_ID);

if (cb.startsWith('email_approve_')) {
  const msgKey = cb.replace('email_approve_', '');
  const draft  = sd.pendingDrafts[msgKey];
  if (!draft) {
    return [{ json: { _emailAction: 'notify', chatId, text: '❌ Borrador no encontrado (puede haber expirado).' } }];
  }
  return [{ json: { _emailAction: 'send', msgKey, to: draft.to, subject: draft.subject, body: draft.body, chatId } }];
}

if (cb.startsWith('email_edit_')) {
  const msgKey = cb.replace('email_edit_', '');
  const draft  = sd.pendingDrafts[msgKey];
  if (!draft) {
    return [{ json: { _emailAction: 'notify', chatId, text: '❌ Borrador no encontrado.' } }];
  }
  sd.pendingEdit = msgKey;
  const prompt = `✏️ *Editar borrador*\n\nEnvíame el texto corregido completo:\n\n_${draft.body.substring(0, 600)}_`;
  return [{ json: { _emailAction: 'notify', chatId, text: prompt } }];
}

return [{ json: { _emailAction: 'notify', chatId, text: '❓ Acción de email desconocida.' } }];

const sd = $getWorkflowStaticData('global');
sd.processedEmails = sd.processedEmails || {};
sd.pendingDrafts   = sd.pendingDrafts   || {};

const { msgKey, to, chatId } = $('Email Callback Handler').first().json;

// Mark as processed, clean up draft
sd.processedEmails[msgKey] = { ts: Date.now(), sentTo: to };
delete sd.pendingDrafts[msgKey];
delete sd.pendingEdit;

const adminId = chatId || String($env.TELEGRAM_ADMIN_ID);
return [{ json: {
  chat_id: adminId,
  text: `✅ Email enviado a ${to}`
} }];

const sd = $getWorkflowStaticData('global');
const inp = items[0].json;
const text = inp.text || '';

// If there's a pending edit AND this message is not a bot command
if (sd.pendingEdit && text && !inp.isCallback) {
  const msgKey = sd.pendingEdit;
  sd.pendingDrafts = sd.pendingDrafts || {};
  const draft = sd.pendingDrafts[msgKey];

  if (draft) {
    // Update the draft body with the new text
    draft.body = text;
    delete sd.pendingEdit;

    const adminId = String($env.TELEGRAM_ADMIN_ID);
    const preview = text.length > 500 ? text.substring(0, 500) + '…' : text;
    const msg = `📧 *Borrador actualizado*\n\n${preview}`;

    // Send re-preview directly via Telegram HTTP API
    const fetch = require('node-fetch');
    await fetch(`https://api.telegram.org/bot${$env.TELEGRAM_BOT_TOKEN}/sendMessage`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        chat_id: adminId,
        text: msg,
        parse_mode: 'Markdown',
        reply_markup: { inline_keyboard: [[
          { text: '✅ Enviar', callback_data: 'email_approve_' + msgKey }
        ]]}
      })
    });

    return []; // Stop — already handled via direct Telegram call
  }
}

// Not a pending edit — pass through normally
return items;

const { text, chatId, tier } = items[0].json;
const lower = (text || '').toLowerCase().trim();

let menuType = '';
let docId = '';

if (lower.startsWith('/taperia') || lower.startsWith('/carta')) {
  menuType = 'taperia';
  // Backward compatibility: many deployments still use MENU_CARTA_DOC_ID.
  docId = $env.MENU_TAPERIA_DOC_ID || $env.MENU_CARTA_DOC_ID || '';
} else if (lower.startsWith('/menu')) {
  menuType = 'menu';
  docId = $env.MENU_MENU_DOC_ID || '';
} else if (lower.startsWith('/bebidas')) {
  menuType = 'bebidas';
  docId = $env.MENU_BEBIDAS_DOC_ID || '';
} else if (lower.startsWith('/desayuno')) {
  menuType = 'desayuno';
  docId = $env.MENU_DESAYUNO_DOC_ID || '';
} else if (lower.startsWith('/streetfood')) {
  menuType = 'streetfood';
  docId = $env.MENU_STREETFOOD_DOC_ID || '';
}

if (!docId || docId.startsWith('REPLACE_')) {
  return [{ json: {
    error: `⚠️ No configurado: añade MENU_${menuType.toUpperCase()}_DOC_ID en las variables de entorno de n8n.`,
    chatId,
    menuType,
    isError: true,
  }}];
}

return [{ json: { menuType, docId, chatId, tier, isError: false } }];

const docText = items[0].json.data || items[0].json.body || '';
const { menuType, chatId } = $('Route Menu Command').first().json;

const taperiaSchema = JSON.stringify({
  updated: "YYYY-MM-DD",
  sections: [{
    name: "Section name",
    note: "optional note",
    items: [{
      name: "Dish name",
      description: "Brief description or empty string",
      price: 0.00,
      allergens: ["gluten","lácteos","huevo","pescado","crustáceos","moluscos","frutos secos","cacahuetes","soja","sulfitos","mostaza","sésamo","apio","altramuces"]
    }]
  }],
  translations: { en: { sections: [] }, fr: { sections: [] }, de: { sections: [] } }
}, null, 2);

const menuSchema = JSON.stringify({
  updated: "YYYY-MM-DD",
  name: "Menú Especial",
  price: 35.00,
  priceNote: "por persona — pan y agua incluidos",
  available: "Sábados y domingos",
  sections: [{
    name: "Course name",
    choose: true,
    note: "optional note",
    items: [{ name: "Dish name", description: "", supplement: null, allergens: [] }]
  }],
  translations: {
    en: { name: "Special Menu", priceNote: "per person — bread and water included", available: "Saturdays and Sundays", sections: [] },
    fr: { name: "Menu Spécial", priceNote: "par personne — pain et eau inclus", available: "Samedis et dimanches", sections: [] },
    de: { name: "Sondermenü", priceNote: "pro Person — Brot und Wasser inklusive", available: "Samstags und sonntags", sections: [] }
  }
}, null, 2);

const bebidasSchema = JSON.stringify({
  updated: "YYYY-MM-DD",
  sections: [{
    name: "Section name",
    items: [{ name: "Item name", description: "", price: 0.00, unit: "copa or botella or null" }]
  }],
  translations: { en: { sections: [] }, fr: { sections: [] }, de: { sections: [] } }
}, null, 2);

const desayunoSchema = JSON.stringify({
  updated: "YYYY-MM-DD",
  sections: [{
    name: "Section name",
    note: "optional note",
    items: [{ name: "Item name", description: "", price: 0.00 }]
  }],
  translations: { en: { sections: [] }, fr: { sections: [] }, de: { sections: [] } }
}, null, 2);

const streetfoodSchema = JSON.stringify({
  updated: "YYYY-MM-DD",
  sections: [{
    name: "Section name",
    items: [{ name: "Item name", description: "", price: 0.00, allergens: [] }]
  }],
  translations: { en: { sections: [] }, fr: { sections: [] }, de: { sections: [] } }
}, null, 2);

const today = new Date().toISOString().split('T')[0];

const prompts = {
  taperia: `You are a structured data extractor for a Spanish restaurant tapas menu.

Convert the following raw text (from a Google Doc) into a valid JSON object matching this exact schema:
${taperiaSchema}

Rules:
- Prices are always numbers (no € symbol)
- If no description exists, use ""
- Allergens: identify from dish name/ingredients. Use only these keys: gluten, lácteos, huevo, pescado, crustáceos, moluscos, frutos secos, cacahuetes, soja, sulfitos, mostaza, sésamo, apio, altramuces
- Keep original Spanish names exactly as written in the "sections" array
- In the translations object, provide EN, FR, and DE versions of section names and each item name/description only. Keep prices and allergen keys unchanged.
- Set updated to today's date (${today})
- Return ONLY the JSON, no explanation, no markdown fences`,

  menu: `You are a structured data extractor for a Spanish restaurant set menu.

Convert the following raw text into a valid JSON object matching this exact schema:
${menuSchema}

Rules:
- Extract the fixed price (number only, no € symbol)
- Extract available days/times from the text if present
- Identify what is included (bread, water, wine, etc.) for priceNote
- Keep course sections in order as they appear
- Set choose: true for courses where guests choose between options
- For items with a surcharge, set supplement to the amount as a number (e.g. 3.00), otherwise null
- Allergens: identify from dish name/ingredients using these keys only: gluten, lácteos, huevo, pescado, crustáceos, moluscos, frutos secos, cacahuetes, soja, sulfitos, mostaza, sésamo, apio, altramuces
- In the translations object, provide EN, FR, and DE versions of name, priceNote, available, and all section/item names and descriptions. Keep prices and allergen keys unchanged.
- Set updated to today's date (${today})
- Return ONLY the JSON, no explanation, no markdown fences`,

  bebidas: `You are a structured data extractor for a Spanish restaurant drinks list.

Convert the following raw text into a valid JSON object matching this exact schema:
${bebidasSchema}

Rules:
- Prices are always numbers (no € symbol)
- unit should be "copa", "botella", or null if not applicable
- If no description exists, use ""
- Group items into logical sections (Vinos Blancos, Vinos Tintos, Vinos Rosados, Cervezas, Refrescos & Agua, Cafés & Infusiones, etc.)
- In the translations object, provide EN, FR, and DE versions of section names and item name/description only. Keep prices unchanged.
- Set updated to today's date (${today})
- Return ONLY the JSON, no explanation, no markdown fences`,

  desayuno: `You are a structured data extractor for a Spanish restaurant breakfast menu.

Convert the following raw text into a valid JSON object matching this exact schema:
${desayunoSchema}

Rules:
- Prices are always numbers (no € symbol)
- If no description exists, use ""
- Group items into logical sections if possible
- In the translations object, provide EN, FR, and DE versions of section names and item name/description only. Keep prices unchanged.
- Set updated to today's date (${today})
- Return ONLY the JSON, no explanation, no markdown fences`,

  streetfood: `You are a structured data extractor for a Spanish restaurant street food menu.

Convert the following raw text into a valid JSON object matching this exact schema:
${streetfoodSchema}

Rules:
- Prices are always numbers (no € symbol)
- If no description exists, use ""
- Allergens: identify from dish name/ingredients. Use only these keys: gluten, lácteos, huevo, pescado, crustáceos, moluscos, frutos secos, cacahuetes, soja, sulfitos, mostaza, sésamo, apio, altramuces
- In the translations object, provide EN, FR, and DE versions of section names and item name/description only. Keep prices and allergen keys unchanged.
- Set updated to today's date (${today})
- Return ONLY the JSON, no explanation, no markdown fences`,
};

return [{ json: {
  prompt: (prompts[menuType] || prompts['taperia']) + '\n\nMENU TEXT:\n' + docText,
  menuType,
  chatId,
} }];

const raw = items[0].json.choices?.[0]?.message?.content || items[0].json.content?.[0]?.text || '';
const finishReason = items[0].json.choices?.[0]?.finish_reason || '';
const usage = items[0].json.usage || {};
const { menuType, chatId } = $('Build Menu Prompt').first().json;

// Strip markdown fences if provider still adds them.
const cleaned = raw.replace(/^```(?:json)?\s*/i, '').replace(/\s*```\s*$/, '').trim();

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (e) {
  const tokenHint = (finishReason === 'length')
    ? ` Posible corte por límite de tokens (finish_reason=length, completion_tokens=${usage.completion_tokens || 'n/a'}).`
    : '';

  return [{ json: {
    isError: true,
    error: `❌ DeepSeek devolvió JSON inválido para /${menuType}. Error: ${e.message}.${tokenHint}\n\nRespuesta raw (primeros 240 chars):\n${raw.slice(0, 240)}`,
    chatId,
    menuType,
  }}];
}

return [{ json: { parsed, menuType, chatId, isError: false } }];

const ctx = $('Menu Parse OK?').first().json;
const { menuType, chatId } = ctx;

const labels = {
  taperia: 'La Tapería', carta: 'La Tapería',
  menu: 'Menú Especial', bebidas: 'Bebidas',
  desayuno: 'Desayuno', streetfood: 'Street Food',
};
const label = labels[menuType] || menuType;
const updatedDate = ctx.parsed?.updated || new Date().toISOString().split('T')[0];
const sectionCount = ctx.parsed?.sections?.length || 0;

return [{ json: {
  chatId,
  text: `✅ *${label} actualizada*\n📅 ${updatedDate} · ${sectionCount} secciones\n🌐 portadirta.com/${menuType}`,
} }];

const { error, chatId } = items[0].json;

const fallback = 'Error al actualizar el menu.';
const raw = String(error || fallback);

// Telegram can reject malformed markdown entities depending on parse mode defaults.
// Force plain-safe text for error messages.
const safe = raw
  .replace(/[\*_`\[\]()~>#+\-=|{}.!]/g, ' ')
  .replace(/\s+/g, ' ')
  .trim()
  .slice(0, 900);

return [{ json: {
  chatId,
  text: safe || fallback,
} }];

// Identity Router: determine user tier before any processing.
// Returns tier: 'admin' | 'collaborator' | 'unauthorized'
const update = items[0].json;
const adminId = $env.TELEGRAM_ADMIN_ID?.toString();
const collabId = $env.TELEGRAM_COLLAB_ID?.toString();

const fromId = (
  update.message?.from?.id ||
  update.callback_query?.from?.id
)?.toString();

const chatId = (
  update.message?.chat?.id ||
  update.callback_query?.message?.chat?.id
)?.toString();

let tier = 'unauthorized';
if (fromId === adminId) tier = 'admin';
else if (collabId && fromId === collabId) tier = 'collaborator';

// Extract callback data if this is a confirm/cancel for a pending action
const callbackData = update.callback_query?.data || '';
const isCallback = !!update.callback_query;
const isVoice = !!(update.message?.voice);
const voiceFileId = update.message?.voice?.file_id || null;
const text = update.message?.text || '';

const isEmailCallback = callbackData.startsWith('email_approve_') || callbackData.startsWith('email_edit_');

// ── Webhook self-heal (runs at most once per hour) ─────────────────────────
try {
  const sd = $getWorkflowStaticData('global');
  const ONE_HOUR = 60 * 60 * 1000;
  if (!sd.lastWebhookCheck || (Date.now() - sd.lastWebhookCheck) > ONE_HOUR) {
    const WEBHOOK_URL = 'https://n8n.hobbitonranch.com/webhook/475cd6ce-bb05-46ee-aea8-663b6e9d8433/webhook';
    const BOT = $env.TELEGRAM_BOT_TOKEN;
    const info = await $helpers.httpRequest({
      method: 'GET',
      url: `https://api.telegram.org/bot${BOT}/getWebhookInfo`
    });
    if (!info.result?.url) {
      await $helpers.httpRequest({
        method: 'POST',
        url: `https://api.telegram.org/bot${BOT}/setWebhook`,
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ url: WEBHOOK_URL, allowed_updates: ['message', 'callback_query'] })
      });
    }
    sd.lastWebhookCheck = Date.now();
  }
} catch(e) { /* non-fatal */ }
// ────────────────────────────────────────────────────────────────────────────

return [{ json: { tier, fromId, chatId, isCallback, isCallbackStr: isCallback ? 'yes' : 'no', callbackData, isEmailCallback, isVoice, voiceFileId, text } }];

const update = items[0].json;
const { callbackData, chatId, tier } = update;

// Not a confirm/cancel callback — drop silently
if (!callbackData || (!callbackData.startsWith('confirm_') && !callbackData.startsWith('cancel_'))) {
  return [[], []];
}

const parts = callbackData.split('_');
const cbAction = parts[0];
const actionKey = parts.slice(1).join('_');

const sd = $getWorkflowStaticData('global');
const pending = sd.pendingActions?.[actionKey];
if (!pending) {
  // output 1 → Telegram Cancelled (expired)
  return [[], [{ json: { message: '⏰ Acción expirada. Vuelve a enviar el comando.', chatId } }]];
}
delete sd.pendingActions[actionKey];

if (cbAction === 'cancel') {
  // output 1 → Telegram Cancelled
  return [[], [{ json: { message: '❌ Acción cancelada.', chatId } }]];
}

// output 0 → Refresh Beds24 Token → execute
return [[{ json: {
  confirmed:     true,
  action:        pending.action,
  endpoint:      pending.endpoint,
  method:        pending.method,
  payload:       pending.payload,
  beds24Payload: pending.beds24Payload || null,
  chatId,
} }], []];

// Download voice OGG and encode as base64 for Gemini multimodal
const fileInfo = items[0].json;
const filePath = fileInfo.result?.file_path;
if (!filePath) throw new Error('Could not get voice file path from Telegram');

const fileUrl = `https://api.telegram.org/file/bot${$env.TELEGRAM_BOT_TOKEN}/${filePath}`;
const resp = await fetch(fileUrl);
if (!resp.ok) throw new Error('Failed to download voice file');
const buffer = Buffer.from(await resp.arrayBuffer());
const base64Audio = buffer.toString('base64');

const { chatId, tier } = $('Identity Router').first().json;
return [{ json: { base64Audio, mimeType: 'audio/ogg', chatId, tier } }];

const deepseekRaw = items[0].json;
const ctx = $('Identity Router').first().json;

let parsed;
try {
  let rawText = deepseekRaw.choices?.[0]?.message?.content || deepseekRaw.content?.[0]?.text || '{}';
  rawText = rawText.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/, '').trim();
  parsed = JSON.parse(rawText);
} catch(e) {
  return [{ json: { validationError: 'DeepSeek returned invalid JSON: ' + e.message, chatId: ctx.chatId } }];
}

// ── Normalize action names ────────────────────────────────────────────────
const actionMap = {
  // beds24
  'getOccupancy':'beds24.getOccupancy','get_occupancy':'beds24.getOccupancy',
  'getPrices':'beds24.getPrices','get_prices':'beds24.getPrices','getRates':'beds24.getPrices','get_rates':'beds24.getPrices',
  'listBookings':'beds24.listBookings','list_bookings':'beds24.listBookings',
  'getArrivals':'beds24.getArrivals','get_arrivals':'beds24.getArrivals',
  'getDepartures':'beds24.getDepartures','get_departures':'beds24.getDepartures',
  'getDailySummary':'beds24.getDailySummary','get_daily_summary':'beds24.getDailySummary','dailySummary':'beds24.getDailySummary',
  'getGuestInfo':'beds24.getGuestInfo','get_guest_info':'beds24.getGuestInfo','guestInfo':'beds24.getGuestInfo',
  'getRevenue':'beds24.getRevenue','get_revenue':'beds24.getRevenue',
  'getOccupancyRate':'beds24.getOccupancyRate','get_occupancy_rate':'beds24.getOccupancyRate','occupancyRate':'beds24.getOccupancyRate',
  'blockRoom':'beds24.blockRoom','block_room':'beds24.blockRoom',
  'updatePrice':'beds24.updatePrice','update_price':'beds24.updatePrice',
  'cancelBooking':'beds24.cancelBooking','cancel_booking':'beds24.cancelBooking',
  // tastyigniter
  'listReservations':'tastyigniter.listReservations','list_reservations':'tastyigniter.listReservations',
  'checkAvailability':'tastyigniter.checkAvailability','check_availability':'tastyigniter.checkAvailability',
  'deleteReservation':'tastyigniter.deleteReservation','delete_reservation':'tastyigniter.deleteReservation',
  'createReservation':'tastyigniter.createReservation','create_reservation':'tastyigniter.createReservation',
  'cancelReservation':'tastyigniter.cancelReservation','cancel_reservation':'tastyigniter.cancelReservation',
  // hievents
  'getTicketCounts':'hievents.getTicketCounts','get_ticket_counts':'hievents.getTicketCounts',
  'listEvents':'hievents.listEvents','list_events':'hievents.listEvents',
  // maintenance
  'addNote':'maintenance.addNote','add_note':'maintenance.addNote',
  'listNotes':'maintenance.listNotes','list_notes':'maintenance.listNotes',
};
const rawAction = parsed.action || '';
if (!rawAction.includes('.') && actionMap[rawAction]) parsed.action = actionMap[rawAction];
const shortAction = rawAction.split('.').pop();
if (rawAction.includes('.') && actionMap[shortAction]) parsed.action = actionMap[shortAction];

// Fuzzy fallback
const knownActions = [
  'beds24.getOccupancy','beds24.getPrices','beds24.listBookings',
  'beds24.getArrivals','beds24.getDepartures','beds24.getDailySummary','beds24.getGuestInfo',
  'beds24.getRevenue','beds24.getOccupancyRate',
  'beds24.blockRoom','beds24.updatePrice','beds24.cancelBooking',
  'tastyigniter.listReservations','tastyigniter.checkAvailability',
  'tastyigniter.deleteReservation','tastyigniter.createReservation','tastyigniter.cancelReservation',
  'hievents.getTicketCounts','hievents.listEvents',
  'maintenance.addNote','maintenance.listNotes','unknown'
];
if (!knownActions.includes(parsed.action)) {
  const a = parsed.action.toLowerCase();
  if      (a.includes('llega') || a.includes('arrival'))   parsed.action = 'beds24.getArrivals';
  else if (a.includes('sale') || a.includes('depart'))     parsed.action = 'beds24.getDepartures';
  else if (a.includes('daily') || a.includes('resumen'))   parsed.action = 'beds24.getDailySummary';
  else if (a.includes('guest') || a.includes('huesped'))   parsed.action = 'beds24.getGuestInfo';
  else if (a.includes('revenue') || a.includes('ingres'))  parsed.action = 'beds24.getRevenue';
  else if (a.includes('rate') || a.includes('tasa'))       parsed.action = 'beds24.getOccupancyRate';
  else if (a.includes('occupan') || a.includes('ocupac'))  parsed.action = 'beds24.getOccupancy';
  else if (a.includes('price') || a.includes('precio') || a.includes('tarif')) parsed.action = 'beds24.getPrices';
  else if (a.includes('booking') || (a.includes('reserv') && a.includes('beds'))) parsed.action = 'beds24.listBookings';
  else if (a.includes('create') || a.includes('nueva reserva') || a.includes('apunta')) parsed.action = 'tastyigniter.createReservation';
  else if (a.includes('cancel') && a.includes('reserv'))  parsed.action = 'tastyigniter.cancelReservation';
  else if (a.includes('reserv'))                           parsed.action = 'tastyigniter.listReservations';
  else if (a.includes('availab') || a.includes('disponib')) parsed.action = 'tastyigniter.checkAvailability';
  else if (a.includes('ticket') || a.includes('event'))   parsed.action = 'hievents.getTicketCounts';
  else if (a.includes('block') || a.includes('bloquea'))  parsed.action = 'beds24.blockRoom';
  else if (a.includes('maintenance') || a.includes('nota')) parsed.action = 'maintenance.addNote';
  else  parsed.action = 'unknown';
}

// ── Endpoint map ──────────────────────────────────────────────────────────
const today = new Date().toISOString().split('T')[0];
const p = parsed.payload || {};
const proxyBase = 'http://restaurant/api/internal';

const endpointMap = {
  'beds24.getOccupancy':      { endpoint: 'https://beds24.com/api/v2/inventory/rooms/availability?propId=318433', method: 'GET' },
  'beds24.getPrices':         { endpoint: 'https://beds24.com/api/v2/inventory/rooms/calendar?propId=318433&includePrices=true&includeNumAvail=true', method: 'GET' },
  'beds24.listBookings':      { endpoint: 'https://beds24.com/api/v2/bookings?propId=318433', method: 'GET' },
  'beds24.getArrivals':       { endpoint: proxyBase + '/daily-summary', method: 'POST' },
  'beds24.getDepartures':     { endpoint: proxyBase + '/daily-summary', method: 'POST' },
  'beds24.getDailySummary':   { endpoint: proxyBase + '/daily-summary', method: 'POST' },
  'beds24.getGuestInfo':      { endpoint: proxyBase + '/guest-info', method: 'POST' },
  'beds24.getRevenue':        { endpoint: 'https://beds24.com/api/v2/bookings?propId=318433', method: 'GET' },
  'beds24.getOccupancyRate':  { endpoint: 'https://beds24.com/api/v2/inventory/rooms/availability?propId=318433&includeNumAvail=true', method: 'GET' },
  'beds24.blockRoom':         { endpoint: 'https://beds24.com/api/v2/inventory/rooms/calendar', method: 'POST' },
  'beds24.updatePrice':       { endpoint: 'https://beds24.com/api/v2/inventory/rooms/calendar', method: 'POST' },
  'beds24.cancelBooking':     { endpoint: 'https://beds24.com/api/v2/bookings/' + (p.bookingId || ''), method: 'DELETE' },
  'tastyigniter.listReservations':   { endpoint: proxyBase + '/reservations', method: 'GET' },
  'tastyigniter.checkAvailability':  { endpoint: proxyBase + '/availability', method: 'GET' },
  'tastyigniter.deleteReservation':  { endpoint: proxyBase + '/reservations/' + (p.reservationId || ''), method: 'DELETE' },
  'tastyigniter.createReservation':  { endpoint: 'http://restaurant/api/public/reservations', method: 'POST' },
  'tastyigniter.cancelReservation':  { endpoint: proxyBase + '/reservations/cancel', method: 'POST' },
  'hievents.getTicketCounts': { endpoint: 'https://events.hobbitonranch.com/api/public/organizers/1/events', method: 'GET' },
  'hievents.listEvents':      { endpoint: 'https://events.hobbitonranch.com/api/public/organizers/1/events', method: 'GET' },
  'maintenance.addNote':      { endpoint: '', method: '', needsApiCall: false },
  'maintenance.listNotes':    { endpoint: '', method: '', needsApiCall: false },
};

if (endpointMap[parsed.action]) {
  const em = endpointMap[parsed.action];
  parsed.endpoint     = em.endpoint;
  parsed.method       = em.method;
  parsed.needsApiCall = em.needsApiCall !== false;
}

// ── Append date params for GET actions ────────────────────────────────────
const startDate = p.startDate || p.date || null;
const endDate   = p.endDate   || p.date || startDate;
if (parsed.action === 'beds24.getOccupancy' || parsed.action === 'beds24.getOccupancyRate') {
  if (startDate) parsed.endpoint += '&startDate=' + startDate + '&endDate=' + endDate;
}
if (parsed.action === 'beds24.getPrices') {
  if (startDate) parsed.endpoint += '&roomId=662792,662793,662794,662795&startDate=' + startDate + '&endDate=' + (endDate || startDate);
  else parsed.endpoint += '&roomId=662792,662793,662794,662795&startDate=' + today + '&endDate=' + today;
}
if (parsed.action === 'beds24.listBookings') {
  if (startDate) parsed.endpoint += '&arrival=' + startDate;
  if (endDate && endDate !== startDate) parsed.endpoint += '&lastNight=' + endDate;
}
if (parsed.action === 'beds24.getRevenue') {
  // firstNight=startDate fetches all bookings arriving on or after startDate
  if (startDate) parsed.endpoint += '&firstNight=' + startDate;
}
if (parsed.action === 'tastyigniter.listReservations') {
  if (startDate) parsed.endpoint += '?startDate=' + startDate + '&endDate=' + (endDate || startDate);
  else parsed.endpoint += '?date=' + today;
}
if (parsed.action === 'tastyigniter.checkAvailability') {
  parsed.endpoint += '?date=' + (startDate || today) + (p.guests ? '&guests=' + p.guests : '');
}

// ── Build beds24Payload for updatePrice / blockRoom ───────────────────────
if (parsed.action === 'beds24.updatePrice' || parsed.action === 'beds24.blockRoom') {
  const roomNameMap = {
    'torre badum':662792,'torre':662792,
    'cala el pebret':662793,'pebret':662793,'el pebret':662793,
    'cala aljub':662794,'aljub':662794,
    'ermita sant antoni':662795,'ermita':662795,'sant antoni':662795,
  };
  let numericRoomId = parseInt(p.roomId);
  if (isNaN(numericRoomId)) {
    const key = (p.roomId || p.roomName || '').toLowerCase().trim();
    numericRoomId = roomNameMap[key] || null;
    if (!numericRoomId) {
      for (const [k, v] of Object.entries(roomNameMap)) {
        if (key.includes(k) || k.includes(key)) { numericRoomId = v; break; }
      }
    }
  }
  const nameFromId = {662792:'Torre Badum',662793:'Cala El Pebret',662794:'Cala Aljub',662795:'Ermita Sant Antoni'};
  parsed.payload.resolvedRoomName = nameFromId[numericRoomId] || p.roomId || p.roomName || 'habitación';
  const from = p.startDate || p.date || '';
  const to   = p.endDate   || p.date || from;
  if (!numericRoomId || !from) {
    return [{ json: { validationError: `No pude identificar la habitación: "${p.roomId || p.roomName}". Usa: Torre Badum, Cala El Pebret, Cala Aljub, Ermita Sant Antoni.`, chatId: ctx.chatId } }];
  }
  if (parsed.action === 'beds24.updatePrice') {
    parsed.beds24Payload = JSON.stringify([{ roomId: numericRoomId, calendar: [{ from, to, price1: parseInt(p.price) }] }]);
  } else {
    parsed.beds24Payload = JSON.stringify([{ roomId: numericRoomId, calendar: [{ from, to, available: 0 }] }]);
  }
}

// ── Permission check ──────────────────────────────────────────────────────
const adminActions = [
  'beds24.getOccupancy','beds24.getPrices','beds24.listBookings',
  'beds24.getArrivals','beds24.getDepartures','beds24.getDailySummary','beds24.getGuestInfo',
  'beds24.getRevenue','beds24.getOccupancyRate',
  'beds24.blockRoom','beds24.updatePrice','beds24.cancelBooking',
  'tastyigniter.listReservations','tastyigniter.checkAvailability',
  'tastyigniter.deleteReservation','tastyigniter.createReservation','tastyigniter.cancelReservation',
  'hievents.getTicketCounts','hievents.listEvents',
  'maintenance.addNote','maintenance.listNotes','unknown'
];
const collabActions = ['beds24.getOccupancy','beds24.getArrivals','beds24.getDepartures','beds24.getDailySummary','tastyigniter.listReservations','tastyigniter.checkAvailability','hievents.getTicketCounts','unknown'];
const allowed = { admin: adminActions, collaborator: collabActions };

// ── Non-command (help/greeting) ───────────────────────────────────────────
const nonCommands = ['unknown', 'greeting', 'chitchat', 'small_talk', 'help', 'none'];
if (nonCommands.includes(parsed.action)) {
  const menu = [
    "👋 *Porta D'irta — Comandos disponibles*",
    '',
    '🏨 *Hotel (Beds24)*',
    '• "¿Cuál es la ocupación de hoy?"',
    '• "¿Cuánto cuesta Torre Badum el 15 de abril?"',
    '• "¿Quién llega hoy / esta semana?"',
    '• "¿Quién sale mañana?"',
    '• "Resumen de hoy"',
    '• "¿Quién está en Cala Aljub ahora?"',
    '• "¿Cuánto hemos facturado este mes?"',
    '• "Tasa de ocupación de julio"',
    '• "Lista las reservas de esta semana"',
    '• "Sube Torre Badum a 150€ del 1 al 15 de junio"',
    '• "Bloquea Ermita Sant Antoni del 1 al 5 de mayo"',
    '',
    '🍽️ *Restaurante (TastyIgniter)*',
    '• "¿Hay reservas de restaurante esta semana?"',
    '• "¿Hay disponibilidad para 4 personas mañana?"',
    '• "Reserva mesa para Juan García, 2 personas, mañana a las 14:00, juan@email.com, 612345678"',
    '• "Cancela la reserva de García"',
    '',
    '🎟️ *Eventos (Hi.Events)*',
    '• "¿Cuántas entradas se han vendido?"',
    '',
    '🔧 *Mantenimiento*',
    '• "Apunta que el grifo de Torre Badum gotea"',
    '• "Lista las notas pendientes"',
  ].join('\n');
  return [{ json: { validationError: menu, chatId: ctx.chatId } }];
}

if (!allowed[ctx.tier]?.includes(parsed.action)) {
  return [{ json: { validationError: `Acción '${parsed.action}' no permitida para tu nivel de acceso.`, chatId: ctx.chatId } }];
}

if (parsed.needsApiCall !== false && (!parsed.endpoint || !parsed.method)) {
  return [{ json: { validationError: 'No se pudo determinar el endpoint para esta acción.', chatId: ctx.chatId } }];
}

return [{ json: { ...parsed, isDestructive: false, confirmationMessage: null, chatId: ctx.chatId, tier: ctx.tier, valid: true, needsApiCall: parsed.needsApiCall !== false } }];

