// Save last exchange to static data for conversation context
try {
  const ctx = $('Schema Validator').first().json;
  const chatId = ctx.chatId || $('Identity Router').first().json.chatId;
  const userMsg = $('Identity Router').first().json.text || '';
  if (chatId && userMsg && ctx.action && ctx.action !== 'unknown') {
    const staticData = $getWorkflowStaticData('global');
    if (!staticData.conversationHistory) staticData.conversationHistory = {};
    staticData.conversationHistory[chatId] = {
      userMessage: userMsg,
      action: ctx.action,
      payload: ctx.payload || {},
      ts: Date.now()
    };
    // Keep max 50 chat histories to avoid bloat
    const keys = Object.keys(staticData.conversationHistory);
    if (keys.length > 50) {
      const oldest = keys.sort((a,b) => (staticData.conversationHistory[a].ts||0) - (staticData.conversationHistory[b].ts||0))[0];
      delete staticData.conversationHistory[oldest];
    }
  }
} catch(e) { /* non-fatal */ }

// Audit log — non-fatal: a crash here must never kill the flow
const ctx = items[0].json;
let actionCtx = {};
try { actionCtx = $('Schema Validator').first().json || {}; } catch(e) {}
try {
  const sd = $getWorkflowStaticData('global');
  if (!sd.auditLog) sd.auditLog = [];
  sd.auditLog.push({
    ts: new Date().toISOString(),
    user: actionCtx.tier || ctx.tier || '?',
    action: actionCtx.action || ctx.action || '?',
    result: ctx.error ? 'error' : 'success',
    n8nExecutionId: $execution.id,
  });
  if (sd.auditLog.length > 500) sd.auditLog = sd.auditLog.slice(-500);
} catch(e) {}
// Pass through: use summary from Format Response or fall back to humanReadableSummary
const summary = ctx.summary || actionCtx.humanReadableSummary || '✅ Completado.';
return [{ json: { ...ctx, summary, chatId: ctx.chatId || actionCtx.chatId } }];

const apiResp = items[0].json;
const ctx = $('Schema Validator').first().json;
const action = ctx.action || '';
const today = new Date().toISOString().split('T')[0];
const p = ctx.payload || {};
const requestedDate = p.date || p.startDate || today;
const endDate = p.endDate || requestedDate;

const roomNames = {662792:'Torre Badum',662793:'Cala El Pebret',662794:'Cala Aljub',662795:'Ermita Sant Antoni'};
const channelEmoji = (ch) => ch === 'bookingdotcom' ? '🌐 Booking' : ch === 'airbnb' ? '🏠 Airbnb' : '✉️ Directo';
const dateLabel = (d) => d === today ? 'hoy' : d;

let summary = '';

// ── beds24.getOccupancy ───────────────────────────────────────────────────
if (action === 'beds24.getOccupancy') {
  const rooms = apiResp.data || [];
  if (!rooms.length) { summary = '📊 No se encontraron datos de ocupación.'; }
  else {
    const lines = rooms.map(room => {
      const avail = room.availability || {};
      const s = avail[requestedDate] ?? avail[today];
      const status = s === true ? '🟢 Libre' : s === false ? '🔴 Ocupada' : '❓';
      return `• ${room.name}: ${status}`;
    });
    summary = `📊 Ocupación ${dateLabel(requestedDate)}:\n` + lines.join('\n');
  }

// ── beds24.getPrices ─────────────────────────────────────────────────────
} else if (action === 'beds24.getPrices') {
  const roomCalendars = apiResp.data || [];
  if (!roomCalendars.length) { summary = '💰 No se encontraron precios para esa fecha.'; }
  else {
    const lines = [];
    for (const rc of roomCalendars) {
      const roomName = roomNames[rc.roomId] || 'Hab.' + rc.roomId;
      const cal = rc.calendar || [];
      if (!cal.length) { lines.push(`• ${roomName}: sin datos`); continue; }
      const entry = cal.find(e => e.day === requestedDate) || cal[0];
      const price = entry.price1 ? `${entry.price1}€/noche` : 'sin precio';
      const numAvail = entry.numAvail !== undefined ? (entry.numAvail > 0 ? '🟢 Libre' : '🔴 Ocupada') : '';
      lines.push(`• ${roomName}: ${price} ${numAvail}`);
    }
    summary = `💰 Precios ${dateLabel(requestedDate)}:\n` + lines.join('\n');
  }

// ── beds24.listBookings ──────────────────────────────────────────────────
} else if (action === 'beds24.listBookings') {
  const bookings = apiResp.data || [];
  if (!bookings.length) { summary = '📋 No hay reservas en el período seleccionado.'; }
  else {
    const lines = bookings.slice(0, 10).map(b => {
      const name = [b.firstName, b.lastName].filter(Boolean).join(' ') || '(sin nombre)';
      const room = roomNames[b.roomId] || `Hab.${b.roomId}`;
      const price = b.price ? `${b.price}€` : '';
      return `• ${name} | ${room} | ${b.arrival}→${b.departure} | ${b.numAdult}👤 ${price} | ${channelEmoji(b.channel||'')}`;
    });
    summary = `📋 Reservas (${bookings.length} total):\n` + lines.join('\n');
    if (bookings.length > 10) summary += `\n... y ${bookings.length - 10} más`;
  }

// ── beds24.getArrivals ───────────────────────────────────────────────────
} else if (action === 'beds24.getArrivals') {
  const arrivals = apiResp.arrivals || [];
  if (!arrivals.length) { summary = `✈️ No hay llegadas para ${dateLabel(requestedDate)}.`; }
  else {
    const lines = arrivals.map(b => `• *${b.name}* → ${b.room} (${b.numAdult}👤) · ${channelEmoji(b.channel||'')}`);
    summary = `✈️ Llegadas ${dateLabel(requestedDate)} (${arrivals.length}):\n` + lines.join('\n');
  }

// ── beds24.getDepartures ─────────────────────────────────────────────────
} else if (action === 'beds24.getDepartures') {
  const departures = apiResp.departures || [];
  if (!departures.length) { summary = `🚪 No hay salidas para ${dateLabel(requestedDate)}.`; }
  else {
    const lines = departures.map(b => `• *${b.name}* ← ${b.room} (${b.numAdult}👤)`);
    summary = `🚪 Salidas ${dateLabel(requestedDate)} (${departures.length}):\n` + lines.join('\n');
  }

// ── beds24.getDailySummary ───────────────────────────────────────────────
} else if (action === 'beds24.getDailySummary') {
  const arrivals   = apiResp.arrivals   || [];
  const departures = apiResp.departures || [];
  const staying    = apiResp.currentlyStaying || [];
  const resos      = apiResp.restaurantReservations || [];
  const parts = [`📅 *Resumen ${dateLabel(requestedDate)}*`];
  parts.push(`\n🏨 Hotel: ${staying.length} habitaciones ocupadas`);
  if (arrivals.length)   parts.push(`✈️ Llegadas: ` + arrivals.map(b => `${b.name} (${b.room})`).join(', '));
  if (departures.length) parts.push(`🚪 Salidas: `  + departures.map(b => `${b.name} (${b.room})`).join(', '));
  if (resos.length)      parts.push(`\n🍽️ Restaurante: ${resos.length} reservas\n` + resos.map(r => `• ${r.time} · ${r.name} · ${r.guests} pers.`).join('\n'));
  else                   parts.push(`\n🍽️ Restaurante: sin reservas`);
  summary = parts.join('\n');

// ── beds24.getGuestInfo ──────────────────────────────────────────────────
} else if (action === 'beds24.getGuestInfo') {
  const roomName = apiResp.roomName || ctx.payload?.resolvedRoomName || 'habitación';
  const guest = apiResp.currentGuest;
  const upcoming = apiResp.upcoming || [];
  if (!guest) {
    summary = `🏠 *${roomName}* está libre hoy (${dateLabel(requestedDate)}).`;
    if (upcoming.length) {
      summary += '\n\nPróxima llegada: ' + upcoming.map(u => `${u.name} · ${u.arrival}→${u.departure}`).join(', ');
    }
  } else {
    summary = `🏠 *${roomName}* — huésped actual:\n• ${guest.name}\n• Check-in: ${guest.arrival} · Check-out: ${guest.departure}\n• ${guest.numAdult}👤 · ${channelEmoji(guest.channel||'')}`;
    if (upcoming.length) {
      summary += '\n\nPróxima reserva: ' + upcoming.map(u => `${u.name} · ${u.arrival}`).join(', ');
    }
  }

// ── beds24.getRevenue ────────────────────────────────────────────────────
} else if (action === 'beds24.getRevenue') {
  const allBookings = apiResp.data || [];
  // Filter: active statuses only (exclude cancelled/deleted)
  const activeStatuses = ['new', 'confirmed', 'checkout', 'checkin'];
  // Filter by date range from payload if available
  const revStart = p.startDate || p.date || null;
  const revEnd   = p.endDate   || p.date || null;
  const bookings = allBookings.filter(b => {
    if (!activeStatuses.includes(b.status)) return false;
    if (revStart && b.arrival < revStart) return false;
    if (revEnd   && b.arrival > revEnd)   return false;
    return true;
  });
  if (!bookings.length) { summary = '💶 No se encontraron reservas activas en ese período.'; }
  else {
    const total = bookings.reduce((sum, b) => sum + (parseFloat(b.price) || 0), 0);
    const roomBreakdown = {};
    for (const b of bookings) {
      const rn = roomNames[b.roomId] || 'Otro';
      roomBreakdown[rn] = (roomBreakdown[rn] || 0) + (parseFloat(b.price) || 0);
    }
    const lines = Object.entries(roomBreakdown).map(([r, v]) => `• ${r}: ${v.toFixed(0)}€`);
    summary = `💶 Ingresos confirmados (${bookings.length} reservas): *${total.toFixed(0)}€*\n` + lines.join('\n');
  }

// ── beds24.getOccupancyRate ──────────────────────────────────────────────
} else if (action === 'beds24.getOccupancyRate') {
  const rooms = apiResp.data || [];
  if (!rooms.length) { summary = '📊 No se encontraron datos de disponibilidad.'; }
  else {
    let totalSlots = 0, occupiedSlots = 0;
    for (const room of rooms) {
      const avail = room.availability || {};
      for (const [date, val] of Object.entries(avail)) {
        totalSlots++;
        if (val === false || val === 0) occupiedSlots++;
      }
    }
    const rate = totalSlots > 0 ? Math.round((occupiedSlots / totalSlots) * 100) : 0;
    summary = `📊 Tasa de ocupación (${requestedDate} → ${endDate}): *${rate}%*\n(${occupiedSlots} noches ocupadas de ${totalSlots} disponibles)`;
  }

// ── beds24.updatePrice ───────────────────────────────────────────────────
} else if (action === 'beds24.updatePrice') {
  const from = p.startDate || p.date || '?';
  const to   = p.endDate   || p.date || from;
  let roomName = '';
  try { roomName = $('Build Beds24 Payload v2').first().json.resolvedRoomName || ''; } catch(e) {}
  roomName = roomName || p.resolvedRoomName || p.roomName || p.roomId || 'habitación';
  const hasError = apiResp.error || apiResp.httpCode >= 400 ||
                   (Array.isArray(apiResp) && apiResp.some(r => r.success === false));
  summary = hasError
    ? `❌ Error al actualizar precio: ${String(apiResp.error || JSON.stringify(apiResp)).slice(0, 120)}`
    : `💰 Precio actualizado: ${roomName} → ${p.price}€/noche (${from} al ${to})`;

// ── beds24.blockRoom ─────────────────────────────────────────────────────
} else if (action === 'beds24.blockRoom') {
  const from = p.startDate || p.date || '?';
  const to   = p.endDate   || p.date || from;
  let roomName = '';
  try { roomName = $('Build Beds24 Payload v2').first().json.resolvedRoomName || ''; } catch(e) {}
  roomName = roomName || p.resolvedRoomName || p.roomName || p.roomId || 'habitación';
  const hasError = apiResp.error || apiResp.httpCode >= 400;
  summary = hasError
    ? `❌ Error al bloquear ${roomName}: ${String(apiResp.error || JSON.stringify(apiResp)).slice(0, 120)}`
    : `🔒 *${roomName}* bloqueada del ${from} al ${to}.`;

// ── tastyigniter.listReservations ────────────────────────────────────────
} else if (action === 'tastyigniter.listReservations') {
  const resos = apiResp.data || [];
  if (!resos.length) { summary = '🍽️ No hay reservas de restaurante.'; }
  else {
    const lines = resos.slice(0, 10).map(r => {
      const name = [r.first_name, r.last_name].filter(Boolean).join(' ') || '(sin nombre)';
      return `• ${r.reserve_date} ${r.reserve_time} · *${name}* · ${r.guest_num} pers.`;
    });
    summary = `🍽️ Reservas restaurante (${resos.length} total):\n` + lines.join('\n');
  }

// ── tastyigniter.checkAvailability ───────────────────────────────────────
} else if (action === 'tastyigniter.checkAvailability') {
  summary = apiResp.available
    ? `✅ Hay disponibilidad para ${requestedDate} (${apiResp.bookedSeats || 0}/${apiResp.capacity || 75} plazas ocupadas).`
    : `❌ Sin disponibilidad para ${requestedDate}. Aforo completo.`;

// ── tastyigniter.createReservation ───────────────────────────────────────
} else if (action === 'tastyigniter.createReservation') {
  if (apiResp.success) {
    const req = p;
    summary = `✅ Reserva creada: *${req.nombre || '?'}* · ${req.fecha || req.date || '?'} a las ${req.hora || '?'} · ${req.guests || req.personas || '?'} personas.`;
  } else {
    summary = `❌ Error al crear reserva: ${apiResp.message || JSON.stringify(apiResp).slice(0,120)}`;
  }

// ── tastyigniter.cancelReservation ───────────────────────────────────────
} else if (action === 'tastyigniter.cancelReservation') {
  if (apiResp.success && apiResp.cancelled) {
    const c = apiResp.cancelled;
    summary = `✅ Reserva cancelada: *${c.name}* del ${c.date} a las ${c.time} (${c.guests} pers.).`;
  } else {
    summary = `❌ ${apiResp.error || 'No se encontró ninguna reserva con ese nombre.'}`;
  }

// ── hievents.getTicketCounts / listEvents ─────────────────────────────────
} else if (action === 'hievents.getTicketCounts' || action === 'hievents.listEvents') {
  const events = apiResp.data || [];
  if (!events.length) { summary = '🎟️ No hay eventos activos.'; }
  else {
    const lines = events.slice(0, 5).map(ev =>
      `• ${ev.title || ev.name}: ${ev.tickets_sold || 0} vendidas / ${ev.capacity || '?'} cap.`
    );
    summary = `🎟️ Eventos (${events.length}):\n` + lines.join('\n');
  }

} else {
  summary = apiResp.success === false
    ? `❌ Error: ${apiResp.error || JSON.stringify(apiResp).slice(0, 200)}`
    : `✅ ${ctx.humanReadableSummary || 'Completado.'}\n\n${JSON.stringify(apiResp).slice(0, 300)}`;
}

// Save conversation context
try {
  const sd = $getWorkflowStaticData('global');
  if (!sd.conversationHistory) sd.conversationHistory = {};
  const chatId = ctx.chatId || $('Identity Router').first().json.chatId || '';
  if (chatId) {
    sd.conversationHistory[chatId] = {
      userMessage: $('Identity Router').first().json.text || '',
