// Loop guard: ignore emails from our own domain
if (from.toLowerCase().includes('portadirta.com')) return [];
// Ignore auto-reply noise
if (/auto.?reply|out of office|delivery.?fail|mailer.?daemon/i.test(subject)) return [];

return [{ json: { msgKey, from, subject, bodyText } }];

