const sd = $getWorkflowStaticData('global');
sd.pendingDrafts   = sd.pendingDrafts   || {};
sd.processedEmails = sd.processedEmails || {};

const cb   = items[0].json.callbackData || '';
const chatId = String(items[0].json.chatId || $env.TELEGRAM_ADMIN_ID);

if (cb.startsWith('email_approve_')) {
  const msgKey = cb.replace('email_approve_', '');
  const draft  = sd.pendingDrafts[msgKey];
  if (!draft) {
    return [{ json: { _emailAction: 'notify', chatId, text: '❌ Borrador no encontrado (puede haber expirado).' } }];
  }
  return [{ json: { _emailAction: 'send', msgKey, to: draft.to, subject: draft.subject, body: draft.body, chatId } }];
}

if (cb.startsWith('email_edit_')) {
  const msgKey = cb.replace('email_edit_', '');
  const draft  = sd.pendingDrafts[msgKey];
  if (!draft) {
    return [{ json: { _emailAction: 'notify', chatId, text: '❌ Borrador no encontrado.' } }];
  }
  sd.pendingEdit = msgKey;
  const prompt = `✏️ *Editar borrador*\n\nEnvíame el texto corregido completo:\n\n_${draft.body.substring(0, 600)}_`;
  return [{ json: { _emailAction: 'notify', chatId, text: prompt } }];
}

return [{ json: { _emailAction: 'notify', chatId, text: '❓ Acción de email desconocida.' } }];

const sd = $getWorkflowStaticData('global');
sd.processedEmails = sd.processedEmails || {};
sd.pendingDrafts   = sd.pendingDrafts   || {};

const { msgKey, to, chatId } = $('Email Callback Handler').first().json;

// Mark as processed, clean up draft
sd.processedEmails[msgKey] = { ts: Date.now(), sentTo: to };
delete sd.pendingDrafts[msgKey];
delete sd.pendingEdit;

const adminId = chatId || String($env.TELEGRAM_ADMIN_ID);
return [{ json: {
  chat_id: adminId,
  text: `✅ Email enviado a ${to}`
} }];

const sd = $getWorkflowStaticData('global');
const inp = items[0].json;
const text = inp.text || '';

// If there's a pending edit AND this message is not a bot command
if (sd.pendingEdit && text && !inp.isCallback) {
  const msgKey = sd.pendingEdit;
  sd.pendingDrafts = sd.pendingDrafts || {};
  const draft = sd.pendingDrafts[msgKey];

  if (draft) {
    // Update the draft body with the new text
    draft.body = text;
    delete sd.pendingEdit;

    const adminId = String($env.TELEGRAM_ADMIN_ID);
    const preview = text.length > 500 ? text.substring(0, 500) + '…' : text;
    const msg = `📧 *Borrador actualizado*\n\n${preview}`;

    // Send re-preview directly via Telegram HTTP API
    const fetch = require('node-fetch');
    await fetch(`https://api.telegram.org/bot${$env.TELEGRAM_BOT_TOKEN}/sendMessage`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        chat_id: adminId,
        text: msg,
        parse_mode: 'Markdown',
        reply_markup: { inline_keyboard: [[
          { text: '✅ Enviar', callback_data: 'email_approve_' + msgKey }
        ]]}
      })
    });

    return []; // Stop — already handled via direct Telegram call
  }
}

// Not a pending edit — pass through normally
return items;
